    sb.append(rtrim(text.substring(0, pos))).append(defaultNewLine);

    // all following lines must be padded with nextLineTabStop space characters
    final String padding = createPadding(nextLineTabStop);

    while (true)
    {
        int lastPos = pos;
        text = padding + text.substring(pos).trim();
        int adjustedPos = findWrapPos(text, width, padding.length());

        if (adjustedPos == -1 || adjustedPos <= padding.length())
        {
            sb.append(rtrim(text.substring(padding.length())));

            return sb;
        }
        else if (adjustedPos == lastPos)
        {
            throw new RuntimeException("Text too long for line - throwing exception to avoid infinite loop [CLI-162]: " + text);
        }

        pos = adjustedPos;
        sb.append(rtrim(text.substring(padding.length(), pos))).append(defaultNewLine);
    }
}

